Create backend/src/lib/chain-registry.ts — the single source of truth for all supported chains.

This module is the foundation for all multi-chain work. Every other component will import from here.

Export:

```typescript
export type ChainType = 'evm' | 'solana';

export interface ChainConfig {
  id: string;           // 'base' | 'polygon' | 'solana'
  displayName: string;
  type: ChainType;
  chainId: number | string;  // number for EVM, 'solana' for Solana
  rpcUrl: string;       // from env var, fallback to public
  usdcAddress: string;  // USDC contract address
  explorerUrl: string;  // for tx links
  usdcDecimals: number; // 6 for both
}

export const CHAINS: Record<string, ChainConfig> = {
  base: {
    id: 'base',
    displayName: 'Base',
    type: 'evm',
    chainId: 8453,
    rpcUrl: process.env.BASE_RPC_URL || 'https://base.gateway.tenderly.co',
    usdcAddress: '0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913',
    explorerUrl: 'https://basescan.org',
    usdcDecimals: 6,
  },
  polygon: {
    id: 'polygon',
    displayName: 'Polygon',
    type: 'evm',
    chainId: 137,
    rpcUrl: process.env.POLYGON_RPC_URL || 'https://polygon-bor-rpc.publicnode.com',
    usdcAddress: '0x3c499c542cEF5E3811e1192ce70d8cC03d5c3359',
    explorerUrl: 'https://polygonscan.com',
    usdcDecimals: 6,
  },
  solana: {
    id: 'solana',
    displayName: 'Solana',
    type: 'solana',
    chainId: 'solana',
    rpcUrl: process.env.SOLANA_RPC_URL || 'https://api.mainnet-beta.solana.com',
    usdcAddress: 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v',
    explorerUrl: 'https://solscan.io',
    usdcDecimals: 6,
  },
};

export function getChain(chainId: string): ChainConfig {
  const chain = CHAINS[chainId];
  if (!chain) throw new Error(`Unsupported chain: ${chainId}. Supported: ${Object.keys(CHAINS).join(', ')}`);
  return chain;
}

export function getSupportedChains(): string[] {
  return Object.keys(CHAINS);
}

export function isEvmChain(chainId: string): boolean {
  return getChain(chainId).type === 'evm';
}

export function isSolanaChain(chainId: string): boolean {
  return getChain(chainId).type === 'solana';
}
```

